1	/**
2	 * SessionManager — manages RpcClient lifecycle for background GSD execution.
3	 *
4	 * One active session per projectDir. Tracks events in a ring buffer,
5	 * detects blockers, tracks terminal state, and accumulates cost using
6	 * the cumulative-max pattern (K004).
7	 */
8	
9	import { execSync } from 'node:child_process';
10	import { resolve } from 'node:path';
11	import { RpcClient } from '@gsd-build/rpc-client';
12	import type { SdkAgentEvent, RpcInitResult, RpcCostUpdateEvent, RpcExtensionUIRequest } from '@gsd-build/rpc-client';
13	import type {
14	  ManagedSession,
15	  ExecuteOptions,
16	  PendingBlocker,
17	  CostAccumulator,
18	  SessionStatus,
19	} from './types.js';
20	import { MAX_EVENTS, INIT_TIMEOUT_MS } from './types.js';
21	
22	// ---------------------------------------------------------------------------
23	// Inlined detection logic (from headless-events.ts — no internal package imports)
24	// ---------------------------------------------------------------------------
25	
26	const FIRE_AND_FORGET_METHODS = new Set([
27	  'notify', 'setStatus', 'setWidget', 'setTitle', 'set_editor_text',
28	]);
29	
30	const TERMINAL_PREFIXES = ['auto-mode stopped', 'step-mode stopped'];
31	
32	function isTerminalNotification(event: Record<string, unknown>): boolean {
33	  if (event.type !== 'extension_ui_request' || event.method !== 'notify') return false;
34	  const message = String(event.message ?? '').toLowerCase();
35	  return TERMINAL_PREFIXES.some((prefix) => message.startsWith(prefix));
36	}
37	
38	function isBlockedNotification(event: Record<string, unknown>): boolean {
39	  if (event.type !== 'extension_ui_request' || event.method !== 'notify') return false;
40	  const message = String(event.message ?? '').toLowerCase();
41	  return message.includes('blocked:');
42	}
43	
44	function isBlockingUIRequest(event: Record<string, unknown>): boolean {
45	  if (event.type !== 'extension_ui_request') return false;
46	  const method = String(event.method ?? '');
47	  return !FIRE_AND_FORGET_METHODS.has(method);
48	}
49	
50	// ---------------------------------------------------------------------------
51	// SessionManager
52	// ---------------------------------------------------------------------------
53	
54	export class SessionManager {
55	  /** Sessions keyed by projectDir for duplicate-start prevention */
56	  private sessions = new Map<string, ManagedSession>();
57	
58	  /**
59	   * Start a new GSD auto-mode session for the given project directory.
60	   *
61	   * Rejects if a session already exists for this projectDir.
62	   * Creates an RpcClient, starts the process, performs the v2 init handshake,
63	   * wires event tracking, and sends '/gsd auto' to begin execution.
64	   */
65	  async startSession(projectDir: string, options: ExecuteOptions = {}): Promise<string> {
66	    if (!projectDir || projectDir.trim() === '') {
67	      throw new Error('projectDir is required and cannot be empty');
68	    }
69	
70	    const resolvedDir = resolve(projectDir);
71	
72	    const existing = this.sessions.get(resolvedDir);
73	    if (existing) {
74	      throw new Error(
75	        `Session already active for ${resolvedDir} (sessionId: ${existing.sessionId}, status: ${existing.status})`
76	      );
77	    }
78	
79	    const cliPath = options.cliPath ?? SessionManager.resolveCLIPath();
80	
81	    const args: string[] = ['--mode', 'rpc'];
82	    if (options.model) args.push('--model', options.model);
83	    if (options.bare) args.push('--bare');
84	
85	    const client = new RpcClient({
86	      cliPath,
87	      cwd: resolvedDir,
88	      args,
89	    });
90	
91	    // Build the session shell before async operations so we can track state
92	    const session: ManagedSession = {
93	      sessionId: '', // filled after init
94	      projectDir: resolvedDir,
95	      status: 'starting',
96	      client,
97	      events: [],
98	      pendingBlocker: null,
99	      cost: { totalCost: 0, tokens: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 } },
100	      startTime: Date.now(),
101	    };
102	
103	    // Insert into map early (keyed by dir) so concurrent starts are rejected
104	    this.sessions.set(resolvedDir, session);
105	
106	    try {
107	      // Start the process with timeout
108	      await Promise.race([
109	        client.start(),
110	        timeout(INIT_TIMEOUT_MS, `RpcClient.start() timed out after ${INIT_TIMEOUT_MS}ms`),
111	      ]);
112	
113	      // Perform v2 init handshake
114	      const initResult: RpcInitResult = await Promise.race([
115	        client.init(),
116	        timeout(INIT_TIMEOUT_MS, `RpcClient.init() timed out after ${INIT_TIMEOUT_MS}ms`),
117	      ]) as RpcInitResult;
118	
119	      session.sessionId = initResult.sessionId;
120	      session.status = 'running';
121	
122	      // Wire event tracking
123	      session.unsubscribe = client.onEvent((event: SdkAgentEvent) => {
124	        this.handleEvent(session, event);
125	      });
126	
127	      // Kick off auto-mode
128	      const command = options.command ?? '/gsd auto';
129	      await client.prompt(command);
130	
131	      return session.sessionId;
132	    } catch (err) {
133	      session.status = 'error';
134	      session.error = err instanceof Error ? err.message : String(err);
135	
136	      // Attempt cleanup
137	      try { await client.stop(); } catch { /* swallow cleanup errors */ }
138	
139	      // Keep session in map so callers can inspect the error
140	      throw new Error(`Failed to start session for ${resolvedDir}: ${session.error}`);
141	    }
142	  }
143	
144	  /**
145	   * Look up a session by sessionId.
146	   * Linear scan is fine — we expect <10 concurrent sessions.
147	   */
148	  getSession(sessionId: string): ManagedSession | undefined {
149	    for (const session of this.sessions.values()) {
150	      if (session.sessionId === sessionId) return session;
151	    }
152	    return undefined;
153	  }
154	
155	  /**
156	   * Look up a session by project directory (direct map lookup).
157	   */
158	  getSessionByDir(projectDir: string): ManagedSession | undefined {
159	    return this.sessions.get(resolve(projectDir));
160	  }
161	
162	  /**
163	   * Resolve a pending blocker by sending a UI response.
164	   */
165	  async resolveBlocker(sessionId: string, response: string): Promise<void> {
166	    const session = this.getSession(sessionId);
167	    if (!session) throw new Error(`Session not found: ${sessionId}`);
168	    if (!session.pendingBlocker) throw new Error(`No pending blocker for session ${sessionId}`);
169	
170	    const blocker = session.pendingBlocker;
171	    session.client.sendUIResponse(blocker.id, { value: response });
172	    session.pendingBlocker = null;
173	    if (session.status === 'blocked') {
174	      session.status = 'running';
175	    }
176	  }
177	
178	  /**
179	   * Cancel a running session — abort current operation then stop the process.
180	   */
181	  async cancelSession(sessionId: string): Promise<void> {
182	    const session = this.getSession(sessionId);
183	    if (!session) throw new Error(`Session not found: ${sessionId}`);
184	
185	    try {
186	      await session.client.abort();
187	    } catch { /* may already be stopped */ }
188	
189	    try {
190	      await session.client.stop();
191	    } catch { /* swallow */ }
192	
193	    session.status = 'cancelled';
194	    session.unsubscribe?.();
195	  }
196	
197	  /**
198	   * Build a HeadlessJsonResult-shaped object from accumulated session state.
199	   */
200	  getResult(sessionId: string): Record<string, unknown> {
201	    const session = this.getSession(sessionId);
202	    if (!session) throw new Error(`Session not found: ${sessionId}`);
203	
204	    const durationMs = Date.now() - session.startTime;
205	
206	    return {
207	      sessionId: session.sessionId,
208	      projectDir: session.projectDir,
209	      status: session.status,
210	      durationMs,
211	      cost: session.cost,
212	      recentEvents: session.events.slice(-10),
213	      pendingBlocker: session.pendingBlocker
214	        ? { id: session.pendingBlocker.id, method: session.pendingBlocker.method, message: session.pendingBlocker.message }
215	        : null,
216	      error: session.error ?? null,
217	    };
218	  }
219	
220	  /**
221	   * Stop all active sessions and clean up resources.
222	   */
223	  async cleanup(): Promise<void> {
224	    const stopPromises: Promise<void>[] = [];
225	
226	    for (const session of this.sessions.values()) {
227	      session.unsubscribe?.();
228	      if (session.status === 'running' || session.status === 'starting' || session.status === 'blocked') {
229	        stopPromises.push(
230	          session.client.stop().catch(() => { /* swallow */ })
231	        );
232	        session.status = 'cancelled';
233	      }
234	    }
235	
236	    await Promise.allSettled(stopPromises);
237	  }
238	
239	  /**
240	   * Resolve the GSD CLI path.
241	   *
242	   * 1. GSD_CLI_PATH env var (highest priority)
243	   * 2. `which gsd` → resolve to the actual dist/cli.js
244	   */
245	  static resolveCLIPath(): string {
246	    // Check env var first
247	    const envPath = process.env['GSD_CLI_PATH'];
248	    if (envPath) return resolve(envPath);
249	
250	    // Fallback: locate `gsd` via which
251	    try {
252	      const gsdBin = execSync('which gsd', { encoding: 'utf-8' }).trim();
253	      if (gsdBin) {
254	        // gsd bin is typically a symlink to dist/loader.js — return the resolved path
255	        return resolve(gsdBin);
256	      }
257	    } catch {
258	      // which failed
259	    }
260	
261	    throw new Error(
262	      'Cannot find GSD CLI. Set GSD_CLI_PATH environment variable or ensure `gsd` is in PATH.'
263	    );
264	  }
265	
266	  // ---------------------------------------------------------------------------
267	  // Private: Event Handling
268	  // ---------------------------------------------------------------------------
269	
270	  private handleEvent(session: ManagedSession, event: SdkAgentEvent): void {
271	    // Ring buffer: push and trim
272	    session.events.push(event);
273	    if (session.events.length > MAX_EVENTS) {
274	      session.events.splice(0, session.events.length - MAX_EVENTS);
275	    }
276	
277	    // Cost tracking (K004 — cumulative-max)
278	    if (event.type === 'cost_update') {
279	      const costEvent = event as unknown as RpcCostUpdateEvent;
280	      session.cost.totalCost = Math.max(session.cost.totalCost, costEvent.cumulativeCost ?? 0);
281	      if (costEvent.tokens) {
282	        session.cost.tokens.input = Math.max(session.cost.tokens.input, costEvent.tokens.input ?? 0);
283	        session.cost.tokens.output = Math.max(session.cost.tokens.output, costEvent.tokens.output ?? 0);
284	        session.cost.tokens.cacheRead = Math.max(session.cost.tokens.cacheRead, costEvent.tokens.cacheRead ?? 0);
285	        session.cost.tokens.cacheWrite = Math.max(session.cost.tokens.cacheWrite, costEvent.tokens.cacheWrite ?? 0);
286	      }
287	    }
288	
289	    // Terminal detection — auto-mode/step-mode stopped
290	    if (isTerminalNotification(event as Record<string, unknown>)) {
291	      // Check if it's a blocked stop (not truly terminal — it's a blocker)
292	      if (isBlockedNotification(event as Record<string, unknown>)) {
293	        session.status = 'blocked';
294	        session.pendingBlocker = extractBlocker(event);
295	      } else {
296	        session.status = 'completed';
297	        session.unsubscribe?.();
298	      }
299	      return;
300	    }
301	
302	    // Blocker detection — non-fire-and-forget extension_ui_request
303	    if (isBlockingUIRequest(event as Record<string, unknown>)) {
304	      session.status = 'blocked';
305	      session.pendingBlocker = extractBlocker(event);
306	    }
307	  }
308	}
309	
310	// ---------------------------------------------------------------------------
311	// Helpers
312	// ---------------------------------------------------------------------------
313	
314	function timeout(ms: number, message: string): Promise<never> {
315	  return new Promise((_, reject) => {
316	    setTimeout(() => reject(new Error(message)), ms);
317	  });
318	}
319	
320	function extractBlocker(event: SdkAgentEvent): PendingBlocker {
321	  const uiEvent = event as unknown as RpcExtensionUIRequest;
322	  return {
323	    id: String(uiEvent.id ?? ''),
324	    method: String(uiEvent.method ?? ''),
325	    message: String((uiEvent as Record<string, unknown>).title ?? (uiEvent as Record<string, unknown>).message ?? ''),
326	    event: uiEvent,
327	  };
328	}
